    global _wifi_state

    if _wifi_state != "CONNECTING":
        return

    if _wlan.isconnected():
        _wifi_state = "CONNECTED"
        return

    if time.ticks_diff(
        time.ticks_ms(),
        _wifi_start_time
    ) > 10000:
        _wifi_state = "FAIL"
