def time_label():
    try:

        t = time.localtime()

        h = t[3] + get_timezone_offset()
        m = t[4]

        if h < 0:
            h += 24

        if h >= 24:
            h -= 24

        return "%02d:%02d" % (h, m)

    except:

        return "--:--"

